17	// Bits indicating the state of a slot:
18	// * If a value has been written into the slot, `WRITE` is set.
19	// * If a value has been read from the slot, `READ` is set.
20	// * If the block is being destroyed, `DESTROY` is set.
21	const WRITE: usize = 1;
22	const READ: usize = 2;
23	const DESTROY: usize = 4;
24	
25	// Each block covers one "lap" of indices.
26	const LAP: usize = 32;
27	// The maximum number of values a block can hold.
28	const BLOCK_CAP: usize = LAP - 1;
29	// How many lower bits are reserved for metadata.
30	const SHIFT: usize = 1;
31	// Indicates that the block is not the last one.
32	const HAS_NEXT: usize = 1;
33	
34	/// A slot in a block.
35	struct Slot<T> {
36	    /// The value.
37	    value: UnsafeCell<MaybeUninit<T>>,
38	
39	    /// The state of the slot.
40	    state: AtomicUsize,
41	}
42	
43	impl<T> Slot<T> {
44	    /// Waits until a value is written into the slot.
45	    fn wait_write(&self) {
46	        let backoff = Backoff::new();
47	        while self.state.load(Ordering::Acquire) & WRITE == 0 {
48	            backoff.snooze();
49	        }
50	    }
51	}
52	
53	/// A block in a linked list.
54	///
55	/// Each block in the list can hold up to `BLOCK_CAP` values.
56	struct Block<T> {
57	    /// The next block in the linked list.
58	    next: AtomicPtr<Block<T>>,
59	
60	    /// Slots for values.
61	    slots: [Slot<T>; BLOCK_CAP],
62	}
63	
64	impl<T> Block<T> {
65	    const LAYOUT: Layout = {
66	        let layout = Layout::new::<Self>();
67	        assert!(
68	            layout.size() != 0,
69	            "Block should never be zero-sized, as it has an AtomicPtr field"
70	        );
71	        layout
72	    };
73	
74	    /// Creates an empty block.
75	    fn new() -> Box<Self> {
76	        // unsafe { Box::new_zeroed().assume_init() } requires Rust 1.92
77	        match Global.allocate_zeroed(Self::LAYOUT) {
78	            Some(ptr) => {
79	                // SAFETY: This is safe because:
80	                //  [1] `Block::next` (AtomicPtr) may be safely zero initialized.
81	                //  [2] `Block::slots` (Array) may be safely zero initialized because of [3, 4].
82	                //  [3] `Slot::value` (UnsafeCell) may be safely zero initialized because it
83	                //       holds a MaybeUninit.
84	                //  [4] `Slot::state` (AtomicUsize) may be safely zero initialized.
85	                unsafe { Box::from_raw(ptr.as_ptr().cast()) }
86	            }
87	            // Handle allocation failure
88	            None => handle_alloc_error(Self::LAYOUT),
89	        }
90	    }
91	
92	    /// Waits until the next pointer is set.
93	    fn wait_next(&self) -> *mut Self {
94	        let backoff = Backoff::new();
95	        loop {
96	            let next = self.next.load(Ordering::Acquire);
97	            if !next.is_null() {
98	                return next;
99	            }
100	            backoff.snooze();
101	        }
102	    }
103	
104	    /// Sets the `DESTROY` bit in slots starting from `start` and destroys the block.
105	    unsafe fn destroy(this: *mut Self, start: usize) {
106	        // It is not necessary to set the `DESTROY` bit in the last slot because that slot has
107	        // begun destruction of the block.
108	        for i in start..BLOCK_CAP - 1 {
109	            let slot = unsafe { (*this).slots.get_unchecked(i) };
110	
111	            // Mark the `DESTROY` bit if a thread is still using the slot.
112	            if slot.state.load(Ordering::Acquire) & READ == 0
113	                && slot.state.fetch_or(DESTROY, Ordering::AcqRel) & READ == 0
114	            {
115	                // If a thread is still using the slot, it will continue destruction of the block.
116	                return;
117	            }
118	        }
119	        // No thread is using the block, now it is safe to destroy it.
120	        drop(unsafe { Box::from_raw(this) });
121	    }
122	
123	    /// Destroys the block. Only safe to call with exclusive access, when no other thread is using it.
124	    unsafe fn destroy_mut(this: *mut Self) {
125	        drop(unsafe { Box::from_raw(this) });
126	    }
127	}
