658	#[derive(Debug)]
659	pub struct IntoIter<T> {
660	    value: SegQueue<T>,
661	}
662	
663	impl<T> Iterator for IntoIter<T> {
664	    type Item = T;
665	
666	    fn next(&mut self) -> Option<Self::Item> {
667	        let value = &mut self.value;
668	        let head = *value.head.index.get_mut();
669	        let tail = *value.tail.index.get_mut();
670	        if head >> SHIFT == tail >> SHIFT {
671	            None
672	        } else {
673	            let block = *value.head.block.get_mut();
674	            let offset = (head >> SHIFT) % LAP;
675	
676	            // SAFETY: We have mutable access to this, so we can read without
677	            // worrying about concurrency. Furthermore, we know this is
678	            // initialized because it is the value pointed at by `value.head`
679	            // and this is a non-empty queue.
680	            let item = unsafe {
681	                let slot = (*block).slots.get_unchecked(offset);
682	                slot.value.get().read().assume_init()
683	            };
684	            if offset + 1 == BLOCK_CAP {
685	                // Deallocate the block and move to the next one.
686	                // SAFETY: The block is initialized because we've been reading
687	                // from it this entire time. We can drop it b/c everything has
688	                // been read out of it, so nothing is pointing to it anymore.
689	                unsafe {
690	                    let next = *(*block).next.get_mut();
691	                    drop(Box::from_raw(block));
692	                    *value.head.block.get_mut() = next;
693	                }
694	                // The last value in a block is empty, so skip it
695	                *value.head.index.get_mut() = head.wrapping_add(2 << SHIFT);
696	                // Double-check that we're pointing to the first item in a block.
697	                debug_assert_eq!((*value.head.index.get_mut() >> SHIFT) % LAP, 0);
698	            } else {
699	                *value.head.index.get_mut() = head.wrapping_add(1 << SHIFT);
700	            }
701	            Some(item)
702	        }
703	    }
