3	// Based on unstable alloc::alloc::Global.
4	//
5	// Note: unlike alloc::alloc::Global that returns NonNull<[u8]>,
6	// this returns NonNull<u8>.
7	pub(crate) struct Global;
8	#[allow(clippy::unused_self)]
9	impl Global {
