11	    #[cfg_attr(miri, track_caller)] // even without panics, this helps for Miri backtraces
12	    fn alloc_impl(&self, layout: Layout, zeroed: bool) -> Option<NonNull<u8>> {
13	        // Layout::dangling is unstable
14	        #[inline]
15	        #[must_use]
